import React, { useState } from 'react';
import Header from './Header';

const Landing = () => {
  const [usuario, setUsuario] = useState(null);

  const handleLogout = () => {
    setUsuario(null);
  };

  return (
    <div style={{ fontFamily: 'Arial, sans-serif', backgroundColor: '#f5f5f5', minHeight: '100vh' }}>
      <Header usuario={usuario} onLogout={handleLogout} />
      <h1>Bienvenido a MAERSK</h1>
      <p>MAERSK es líder mundial en transporte marítimo y soluciones logísticas. Conectamos negocios a
        través de una red global de más de 130 países.</p>
      <div style={{ margin: '20px 0' }}>
        <h2>¿Qué puedes hacer aquí?</h2>
        <ul style={{ listStyleType: 'none', padding: 0 }}>
          <li>� Transporte de mercancías a nivel mundial</li>
          <li>⚓ Servicios portuarios y logística</li>
          <li>🌍 Cobertura en más de 130 países</li>
          <li>📦 Gestión de cadena de suministro eficiente</li>
        </ul>
      </div>
      <div>
        <a href="/home" style={{ margin: '0 10px', padding: '10px 20px', backgroundColor: 
            '#6f42c1', color: 'white', textDecoration: 'none', borderRadius: '5px' }}>
          Ir al Inicio
        </a>
        <a href="/simple" style={{ margin: '0 10px', padding: '10px 20px', backgroundColor: 
            '#007bff', color: 'white', textDecoration: 'none', borderRadius: '5px' }}>
          Contador TEUs
        </a>
        <a href="/test" style={{ margin: '0 10px', padding: '10px 20px', backgroundColor: 
            '#28a745', color: 'white', textDecoration: 'none', borderRadius: '5px' }}>
          Servicios
        </a>
        <a href="/signup" style={{ margin: '0 10px', padding: '10px 20px', backgroundColor: 
            '#dc3545', color: 'white', textDecoration: 'none', borderRadius: '5px' }}>
          Registrarse
        </a>
      </div>
    </div>
  );
};

export default Landing;
